17	 * @property {SyncBailHook<[string, string, EntryDescription], string | undefined>} entry transform an entry into a different request (e.g. wrap a non-HTML entry in a synthetic HTML module); return `undefined` to keep the default behavior
18	 */
19	
20	const PLUGIN_NAME = "EntryOptionPlugin";
21	
22	/** @type {WeakMap<Compiler, EntryOptionPluginHooks>} */
23	const hooksMap = new WeakMap();
24	
25	class EntryOptionPlugin {
26		/**
27		 * @param {Compiler} compiler the compiler
28		 * @returns {EntryOptionPluginHooks} the hooks
29		 */
30		static getHooks(compiler) {
31			let hooks = hooksMap.get(compiler);
32			if (hooks === undefined) {
33				hooks = {
34					entry: new SyncBailHook(["context", "name", "entryDescription"])
35				};
36				hooksMap.set(compiler, hooks);
37			}
38			return hooks;
39		}
40	
41		/**
42		 * Applies the plugin by registering its hooks on the compiler.
43		 * @param {Compiler} compiler the compiler instance one is tapping into
44		 * @returns {void}
45		 */
46		apply(compiler) {
47			compiler.hooks.entryOption.tap(PLUGIN_NAME, (context, entry) => {
48				EntryOptionPlugin.applyEntryOption(compiler, context, entry);
49				return true;
50			});
51		}
52	
53		/**
54		 * Apply entry option.
55		 * @param {Compiler} compiler the compiler
56		 * @param {string} context context directory
57		 * @param {Entry} entry request
58		 * @returns {void}
59		 */
60		static applyEntryOption(compiler, context, entry) {
61			if (typeof entry === "function") {
62				const DynamicEntryPlugin = require("./DynamicEntryPlugin");
63	
64				new DynamicEntryPlugin(context, entry).apply(compiler);
65			} else {
66				const EntryPlugin = require("./EntryPlugin");
67	
68				for (const name of Object.keys(entry)) {
69					const desc = entry[name];
70					const options = EntryOptionPlugin.entryDescriptionToOptions(
71						compiler,
72						name,
73						desc
74					);
75					const descImport =
76						/** @type {Exclude<EntryDescription["import"], undefined>} */
77						(desc.import);
78					// A plugin (e.g. HtmlModulesPlugin) may rewrite the entry into a
79					// single synthetic request; otherwise each import becomes an entry.
80					const request = EntryOptionPlugin.getHooks(compiler).entry.call(
81						context,
82						name,
83						desc
84					);
85					if (request !== undefined) {
86						new EntryPlugin(context, request, options).apply(compiler);
87					} else {
88						for (const entry of descImport) {
89							new EntryPlugin(context, entry, options).apply(compiler);
90						}
91					}
92				}
93			}
94		}
95	
96		/**
97		 * Entry description to options.
98		 * @param {Compiler} compiler the compiler
99		 * @param {string} name entry name
100		 * @param {EntryDescription} desc entry description
101		 * @returns {EntryOptions} options for the entry
102		 */
103		static entryDescriptionToOptions(compiler, name, desc) {
104			/** @type {EntryOptions} */
105			const options = {
106				name,
107				filename: desc.filename,
108				runtime: desc.runtime,
109				layer: desc.layer,
110				dependOn: desc.dependOn,
111				baseUri: desc.baseUri,
112				publicPath: desc.publicPath,
113				chunkLoading: desc.chunkLoading,
114				asyncChunks: desc.asyncChunks,
115				wasmLoading: desc.wasmLoading,
116				worker: desc.worker,
117				library: desc.library
118			};
119			if (desc.chunkLoading) {
120				const EnableChunkLoadingPlugin = require("./javascript/EnableChunkLoadingPlugin");
121	
122				EnableChunkLoadingPlugin.checkEnabled(compiler, desc.chunkLoading);
123			}
124			if (desc.wasmLoading) {
125				const EnableWasmLoadingPlugin = require("./wasm/EnableWasmLoadingPlugin");
126	
127				EnableWasmLoadingPlugin.checkEnabled(compiler, desc.wasmLoading);
128			}
129			if (desc.library) {
130				const EnableLibraryPlugin = require("./library/EnableLibraryPlugin");
131	
132				EnableLibraryPlugin.checkEnabled(compiler, desc.library.type);
133			}
134			return options;
135		}
136	}
137	
138	module.exports = EntryOptionPlugin;
