	deserialize(context) {
		this.dependencies = context.read();
		const c1 = context.rest;
		this.name = c1.read();
		super.deserialize(c1.rest);
	}
}

makeSerializable(
	DllEntryDependency,
	"webpack/lib/dependencies/DllEntryDependency"
);

module.exports = DllEntryDependency;

